from dataclasses import dataclassfrom collections.abc import Iteratorfrom criresviz.database.loader import load_settings_databasefrom .order import Orderfrom .detector import Detector@dataclass(slots=True)class CRIRESSetting:    """    Representation of a CRIRES+ wavelength setting.    A CRIRES+ setting consists of several echelle orders, each split across    three detectors. Instances are typically created using    :meth:`from_name`, which loads the instrument configuration from the    bundled CRIRES+ database.    Parameters    ----------    name : str        CRIRES+ setting name (e.g. ``"L3262"``).    band : str        Spectral band of the setting.    reference_wavelength : float        Central wavelength of the setting in μm.    orders : list[Order]        List of echelle orders belonging to the setting.    """        name: str    band: str    reference_wavelength: float    orders: list[Order]        # properties        @property    def wavelength_range(self):        """        Overall wavelength coverage of the setting.        Returns        -------        tuple[float, float]            Minimum and maximum wavelength covered by all orders.        """        return (            min(order.wavelength_min for order in self.orders),            max(order.wavelength_max for order in self.orders),        )    @property    def order_numbers(self):        """Return the available echelle order numbers."""        return [order.number for order in self.orders]            @property    def n_orders(self):        """Number of echelle orders."""        return len(self.orders)        # constructors        @classmethod    def from_name(cls, name: str):        """        Load a CRIRES+ setting from the internal database.        Parameters        ----------        name : str            CRIRES+ setting name (e.g. ``"M4368"``).        Returns        -------        CRIRESSetting            Fully initialized setting containing all orders and detectors.        Raises        ------        KeyError            If the requested setting does not exist in the database.        """        database = load_settings_database()        info = database[name]        orders = []                for order_number, order_info in info["orders"].items():                    detector1 = Detector(                number=1,                wavelength_min=order_info["detector1"]["min"],                wavelength_max=order_info["detector1"]["max"],            )                    detector2 = Detector(                number=2,                wavelength_min=order_info["detector2"]["min"],                wavelength_max=order_info["detector2"]["max"],            )                    detector3 = Detector(                number=3,                wavelength_min=order_info["detector3"]["min"],                wavelength_max=order_info["detector3"]["max"],            )                    orders.append(                Order(                    number=int(order_number),                    detector1=detector1,                    detector2=detector2,                    detector3=detector3,                )            )                    orders = sorted(            orders,            key=lambda order: order.number,            reverse=True,            )        return cls(            name=name,            band=info["band"],            reference_wavelength=info["reference_wavelength"],            orders=orders        )        # public methods        def __iter__(self) -> Iterator[Order]:        """        Iterate over the echelle orders.                Yields        ------        Order            Orders belonging to the setting.        """        return iter(self.orders)    ##############################################    def get_order(self, number: int) -> Order:        """        Return a specific echelle order.        Parameters        ----------        number : int            Order number.        Returns        -------        Order            Requested order.        Raises        ------        ValueError            If the order is not present in the setting.        """            for order in self.orders:                if order.number == number:                return order            raise ValueError(            f"Order {number} not found."        )    # dunder methods        def __str__(self):            return (            "CRIRES+ Setting\n"            "──────────────────────────────\n"            f"Name:                 {self.name}\n"            f"Band:                 {self.band}\n"            f"Reference wavelength:   {self.reference_wavelength:.3f} μm\n"                        f"Orders:               {len(self.orders)}\n"            f"Wavelength range:     "            f"{self.wavelength_range[0]:.3f}–"            f"{self.wavelength_range[1]:.3f} μm"        )    